<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu-ish Desktop</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { width: 100%; height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", system-ui, sans-serif;
    color: #f2f2f2;
    user-select: none;
  }

  /* Desktop */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(circle at 25% 20%, #5a2b4d 0%, rgba(90,43,77,0) 55%),
      radial-gradient(circle at 80% 75%, #772c1d 0%, rgba(119,44,29,0) 50%),
      linear-gradient(135deg, #2c001e 0%, #3a0f2a 45%, #77216f 100%);
    overflow: hidden;
  }

  /* Taskbar / dock */
  #taskbar {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 48px;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 0 14px;
    background: rgba(20, 12, 20, 0.85);
    backdrop-filter: blur(8px);
    border-bottom: 1px solid rgba(255,255,255,0.08);
    z-index: 10000;
  }
  #taskbar .brand {
    font-weight: 700;
    margin-right: 12px;
    letter-spacing: 0.3px;
    color: #e95420;
  }
  #taskbar button {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    height: 34px;
    padding: 0 14px;
    border: 1px solid rgba(255,255,255,0.12);
    border-radius: 8px;
    background: rgba(255,255,255,0.06);
    color: #f2f2f2;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s, transform 0.05s;
  }
  #taskbar button:hover { background: rgba(233,84,32,0.35); }
  #taskbar button:active { transform: translateY(1px); }
  #taskbar .ico {
    width: 16px; height: 16px;
    display: inline-block;
    border-radius: 4px;
  }
  #taskbar .clock {
    margin-left: auto;
    font-size: 13px;
    opacity: 0.85;
    font-variant-numeric: tabular-nums;
  }

  /* Windows */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    width: 640px;
    height: 440px;
    background: #2b2b2b;
    border: 1px solid rgba(255,255,255,0.12);
    border-radius: 10px;
    box-shadow: 0 18px 50px rgba(0,0,0,0.55);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .window.show { display: flex; }
  .titlebar {
    height: 38px;
    flex: 0 0 38px;
    display: flex;
    align-items: center;
    padding: 0 10px;
    background: linear-gradient(#3d3d3d, #333);
    border-bottom: 1px solid rgba(0,0,0,0.4);
    cursor: move;
  }
  .titlebar .title {
    font-size: 13px;
    font-weight: 600;
    opacity: 0.92;
  }
  .titlebar .win-btns {
    margin-left: auto;
    display: flex;
    gap: 8px;
  }
  .titlebar .win-btns button {
    width: 16px; height: 16px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
  }
  .win-min { background: #f6b73c; }
  .win-max { background: #29c940; }
  .win-close { background: #ff5f57; }
  .win-body { flex: 1 1 auto; display: flex; min-height: 0; }

  /* Files app */
  .files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: #262626;
    border-bottom: 1px solid rgba(255,255,255,0.07);
  }
  .files-toolbar button {
    height: 28px; padding: 0 12px;
    border: 1px solid rgba(255,255,255,0.12);
    background: rgba(255,255,255,0.06);
    color: #eee; border-radius: 6px; cursor: pointer; font-size: 12px;
  }
  .files-toolbar button:hover { background: rgba(255,255,255,0.14); }
  #files-path {
    flex: 1;
    padding: 6px 10px;
    background: #1c1c1c;
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 6px;
    font-family: "Ubuntu Mono", monospace;
    font-size: 12px;
    color: #9fe0a0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  #files-inner { display: flex; flex-direction: column; min-height: 0; flex: 1; }
  #files-list {
    flex: 1;
    overflow: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 8px;
    align-content: start;
  }
  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    padding: 10px 6px;
    border-radius: 8px;
    cursor: pointer;
    text-align: center;
    transition: background 0.1s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(233,84,32,0.35); }
  .fs-item .glyph {
    width: 44px; height: 36px;
    display: flex; align-items: center; justify-content: center;
    font-size: 30px; line-height: 1;
  }
  .fs-item .label {
    font-size: 12px;
    word-break: break-word;
    max-width: 90px;
  }
  #files-empty {
    padding: 20px; opacity: 0.6; font-size: 13px;
  }

  /* Notepad app */
  #notepad-window .win-body { flex-direction: column; }
  #tabs {
    display: flex;
    align-items: stretch;
    gap: 2px;
    padding: 6px 6px 0;
    background: #262626;
    overflow-x: auto;
    flex: 0 0 auto;
    min-height: 38px;
  }
  .tab {
    display: flex;
    align-items: center;
    gap: 8px;
    max-width: 180px;
    padding: 6px 10px;
    background: #333;
    border: 1px solid rgba(255,255,255,0.08);
    border-bottom: none;
    border-radius: 7px 7px 0 0;
    cursor: pointer;
    font-size: 12px;
    white-space: nowrap;
  }
  .tab .tab-name {
    overflow: hidden; text-overflow: ellipsis; white-space: nowrap;
  }
  .tab.active { background: #1e1e1e; color: #fff; }
  .tab .tab-close {
    border: none; background: transparent; color: #bbb;
    cursor: pointer; font-size: 14px; line-height: 1; padding: 0 2px;
    border-radius: 4px;
  }
  .tab .tab-close:hover { background: rgba(255,255,255,0.15); color: #fff; }
  #new-tab {
    flex: 0 0 auto;
    width: 30px;
    border: 1px solid rgba(255,255,255,0.08);
    border-bottom: none;
    background: #2b2b2b;
    color: #eee;
    font-size: 18px;
    cursor: pointer;
    border-radius: 7px 7px 0 0;
  }
  #new-tab:hover { background: rgba(233,84,32,0.35); }
  #editor {
    flex: 1 1 auto;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    padding: 14px;
    background: #1e1e1e;
    color: #eaeaea;
    font-family: "Ubuntu Mono", monospace;
    font-size: 14px;
    line-height: 1.5;
  }
</style>
</head>
<body>
<div id="desktop">

  <div id="taskbar">
    <span class="brand">◉ Ubuntu</span>
    <button id="open-files"><span class="ico" style="background:#e95420"></span>Files</button>
    <button id="open-notepad"><span class="ico" style="background:#77216f"></span>Notepad</button>
    <span class="clock" id="clock"></span>
  </div>

  <!-- Files window -->
  <div class="window" id="files-window" style="left:120px; top:90px;">
    <div class="titlebar">
      <span class="title">Files</span>
      <div class="win-btns">
        <button class="win-min" title="minimize"></button>
        <button class="win-max" title="maximize"></button>
        <button class="win-close" title="close"></button>
      </div>
    </div>
    <div class="win-body">
      <div id="files-inner">
        <div class="files-toolbar">
          <button id="files-up" title="Up">↑ Up</button>
          <div id="files-path">/</div>
        </div>
        <div id="files-list"></div>
      </div>
    </div>
  </div>

  <!-- Notepad window -->
  <div class="window" id="notepad-window" style="left:230px; top:150px;">
    <div class="titlebar">
      <span class="title">Notepad</span>
      <div class="win-btns">
        <button class="win-min" title="minimize"></button>
        <button class="win-max" title="maximize"></button>
        <button class="win-close" title="close"></button>
      </div>
    </div>
    <div class="win-body">
      <div id="tabs"></div>
      <textarea id="editor" spellcheck="false" placeholder="Start typing…"></textarea>
    </div>
  </div>

</div>

<script>
(function () {
  "use strict";

  /* ---------------- Clock ---------------- */
  const clockEl = document.getElementById("clock");
  function tick() {
    const d = new Date();
    const opts = { weekday: "short", hour: "2-digit", minute: "2-digit" };
    clockEl.textContent = d.toLocaleString(undefined, opts);
  }
  tick();
  setInterval(tick, 15000);

  /* ---------------- Window management ---------------- */
  let zTop = 100;
  function focusWindow(win) {
    zTop += 1;
    win.style.zIndex = zTop;
  }
  function showWindow(win) {
    win.classList.add("show");
    focusWindow(win);
  }
  function hideWindow(win) {
    win.classList.remove("show");
  }

  document.querySelectorAll(".window").forEach(function (win) {
    win.addEventListener("mousedown", function () { focusWindow(win); });
    win.querySelector(".win-close").addEventListener("click", function (e) {
      e.stopPropagation();
      hideWindow(win);
    });
    // Maximize toggle
    const maxBtn = win.querySelector(".win-max");
    let prev = null;
    maxBtn.addEventListener("click", function (e) {
      e.stopPropagation();
      if (prev) {
        Object.assign(win.style, prev);
        prev = null;
      } else {
        prev = { left: win.style.left, top: win.style.top, width: win.style.width, height: win.style.height };
        win.style.left = "0px";
        win.style.top = "48px";
        win.style.width = "100%";
        win.style.height = "calc(100% - 48px)";
      }
    });
    // Minimize just hides
    win.querySelector(".win-min").addEventListener("click", function (e) {
      e.stopPropagation();
      hideWindow(win);
    });
    makeDraggable(win, win.querySelector(".titlebar"));
  });

  function makeDraggable(win, handle) {
    let dragging = false, offX = 0, offY = 0;
    handle.addEventListener("mousedown", function (e) {
      if (e.target.closest(".win-btns")) return;
      dragging = true;
      const rect = win.getBoundingClientRect();
      offX = e.clientX - rect.left;
      offY = e.clientY - rect.top;
      focusWindow(win);
      e.preventDefault();
    });
    window.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      let x = e.clientX - offX;
      let y = e.clientY - offY;
      x = Math.max(0, Math.min(x, window.innerWidth - 60));
      y = Math.max(48, Math.min(y, window.innerHeight - 40));
      win.style.left = x + "px";
      win.style.top = y + "px";
    });
    window.addEventListener("mouseup", function () { dragging = false; });
  }

  const filesWindow = document.getElementById("files-window");
  const notepadWindow = document.getElementById("notepad-window");
  document.getElementById("open-files").addEventListener("click", function () { showWindow(filesWindow); });
  document.getElementById("open-notepad").addEventListener("click", function () {
    showWindow(notepadWindow);
    renderTabs();
    loadActiveIntoEditor();
  });

  /* ---------------- Files app (fake filesystem) ---------------- */
  // A folder is an object; a file is a string (its display name maps to type by absence of children)
  const FS = {
    bin: { "bash": null, "ls": null, "cat": null, "grep": null },
    etc: { "hostname": null, "hosts": null, "passwd": null, "fstab": null },
    home: {
      user: {
        Documents: { "resume.pdf": null, "notes.txt": null, "budget.xlsx": null },
        Downloads: { "ubuntu-24.04.iso": null, "photo.zip": null },
        Pictures: { "wallpaper.png": null, "avatar.jpg": null, "screenshots": { "shot1.png": null } },
        Music: { "song.mp3": null },
        ".bashrc": null,
        "todo.txt": null
      }
    },
    usr: {
      bin: { "python3": null, "node": null, "vim": null },
      lib: { "libc.so": null },
      share: { doc: { "README": null } }
    },
    var: {
      log: { "syslog": null, "auth.log": null },
      tmp: {},
      www: { html: { "index.html": null } }
    }
  };

  const pathEl = document.getElementById("files-path");
  const listEl = document.getElementById("files-list");
  let currentPath = []; // array of segments; [] === "/"

  function resolve(segs) {
    let node = FS;
    for (const s of segs) {
      if (node && typeof node === "object" && s in node) {
        node = node[s];
      } else {
        return null;
      }
    }
    return node;
  }

  function isFolder(node) {
    return node !== null && typeof node === "object";
  }

  function pathString(segs) {
    return "/" + segs.join("/");
  }

  function renderFiles() {
    pathEl.textContent = pathString(currentPath);
    const node = resolve(currentPath);
    listEl.innerHTML = "";
    if (!isFolder(node)) {
      const empty = document.createElement("div");
      empty.id = "files-empty";
      empty.textContent = "(not a directory)";
      listEl.appendChild(empty);
      return;
    }
    const names = Object.keys(node).sort(function (a, b) {
      const fa = isFolder(node[a]) ? 0 : 1;
      const fb = isFolder(node[b]) ? 0 : 1;
      if (fa !== fb) return fa - fb;
      return a.localeCompare(b);
    });
    if (names.length === 0) {
      const empty = document.createElement("div");
      empty.id = "files-empty";
      empty.textContent = "(empty folder)";
      listEl.appendChild(empty);
      return;
    }
    names.forEach(function (name) {
      const folder = isFolder(node[name]);
      const item = document.createElement("div");
      item.className = "fs-item";
      item.dataset.name = name;
      item.dataset.folder = folder ? "1" : "0";

      const glyph = document.createElement("div");
      glyph.className = "glyph";
      glyph.textContent = folder ? "📁" : "📄";

      const label = document.createElement("div");
      label.className = "label";
      label.textContent = name;

      item.appendChild(glyph);
      item.appendChild(label);

      item.addEventListener("click", function () {
        listEl.querySelectorAll(".fs-item.selected").forEach(function (el) { el.classList.remove("selected"); });
        item.classList.add("selected");
      });
      item.addEventListener("dblclick", function () {
        if (folder) {
          currentPath = currentPath.concat(name);
          renderFiles();
        }
      });

      listEl.appendChild(item);
    });
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath.length > 0) {
      currentPath = currentPath.slice(0, -1);
      renderFiles();
    }
  });

  renderFiles();

  /* ---------------- Notepad app (persistent tabs) ---------------- */
  const STORE_KEY = "ubuntu_notepad_state_v1";
  const tabsEl = document.getElementById("tabs");
  const editor = document.getElementById("editor");

  let state = loadState();

  function loadState() {
    try {
      const raw = localStorage.getItem(STORE_KEY);
      if (raw) {
        const parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length > 0) {
          if (typeof parsed.activeId === "undefined" ||
              !parsed.tabs.some(function (t) { return t.id === parsed.activeId; })) {
            parsed.activeId = parsed.tabs[0].id;
          }
          if (typeof parsed.seq !== "number") parsed.seq = parsed.tabs.length;
          return parsed;
        }
      }
    } catch (e) { /* ignore corrupt data */ }
    return { tabs: [{ id: 1, name: "Untitled 1", content: "" }], activeId: 1, seq: 1 };
  }

  function saveState() {
    try { localStorage.setItem(STORE_KEY, JSON.stringify(state)); } catch (e) {}
  }

  function activeTab() {
    return state.tabs.find(function (t) { return t.id === state.activeId; });
  }

  function renderTabs() {
    // Keep the #new-tab button out of #tabs so its ID contract is clean; we rebuild tab elements only.
    tabsEl.innerHTML = "";
    state.tabs.forEach(function (t) {
      const tab = document.createElement("div");
      tab.className = "tab" + (t.id === state.activeId ? " active" : "");
      tab.dataset.id = t.id;

      const nameSpan = document.createElement("span");
      nameSpan.className = "tab-name";
      nameSpan.textContent = t.name;

      const closeBtn = document.createElement("button");
      closeBtn.className = "tab-close";
      closeBtn.textContent = "×";
      closeBtn.title = "Close tab";

      tab.appendChild(nameSpan);
      tab.appendChild(closeBtn);

      tab.addEventListener("click", function (e) {
        if (e.target === closeBtn) return;
        state.activeId = t.id;
        saveState();
        renderTabs();
        loadActiveIntoEditor();
      });
      closeBtn.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(t.id);
      });

      tabsEl.appendChild(tab);
    });

    // New-tab button (must have id #new-tab and live in tab strip)
    const addBtn = document.createElement("button");
    addBtn.id = "new-tab";
    addBtn.textContent = "+";
    addBtn.title = "New tab";
    addBtn.addEventListener("click", newTab);
    tabsEl.appendChild(addBtn);
  }

  function loadActiveIntoEditor() {
    const t = activeTab();
    editor.value = t ? t.content : "";
  }

  function newTab() {
    state.seq += 1;
    const id = Date.now ? state.seq : state.seq; // seq is monotonic, avoids Date use
    const t = { id: state.seq, name: "Untitled " + state.seq, content: "" };
    state.tabs.push(t);
    state.activeId = t.id;
    saveState();
    renderTabs();
    loadActiveIntoEditor();
    editor.focus();
  }

  function closeTab(id) {
    const idx = state.tabs.findIndex(function (t) { return t.id === id; });
    if (idx === -1) return;
    state.tabs.splice(idx, 1);
    if (state.tabs.length === 0) {
      state.seq += 1;
      state.tabs.push({ id: state.seq, name: "Untitled " + state.seq, content: "" });
      state.activeId = state.seq;
    } else if (state.activeId === id) {
      state.activeId = state.tabs[Math.max(0, idx - 1)].id;
    }
    saveState();
    renderTabs();
    loadActiveIntoEditor();
  }

  editor.addEventListener("input", function () {
    const t = activeTab();
    if (t) {
      t.content = editor.value;
      saveState();
    }
  });

  // Initialize notepad UI (works even before window shown)
  renderTabs();
  loadActiveIntoEditor();
})();
</script>
</body>
</html>
